components.calculateValue:
const selectedDisabilityCategoryKeys = Object.keys(data.disabilityCategories || {}).filter((key) => data.disabilityCategories[key]);

if(selectedDisabilityCategoryKeys.length){
  // Map of required document IDs to their corresponding HTML list items.
  const requiredDocumentsMap = {
    1: '<li>Verification of <a rel="noopener" target="_blank" href="https://studentaidbc.ca/sites/all/files/form-library/disability-verification.pdf">disability form</a> completed by a valid assessor.</li>',
    2: '<li>Psycho-education assessment completed within the last 5 years, or when you were 18 years of age or older.</li>',
    3: '<li>A copy of your most recent visual acuity report.</li>',
    4: '<li>A copy of your most recent audiology report.</li>',
  };
 // Map of disability categories to their required document IDs.
  const disabilityCategoryRequiredDocumentsMap = {
    "specificLearningDisorder": [2],
    "visualConditions": [1, 3],
    "auditoryConditions": [1, 4],
    "otherDisablingConditions": [1],
  };
  // Create a set to store unique required document IDs based on the selected disability categories.
  const uniqueDocIds = new Set(
    selectedDisabilityCategoryKeys.flatMap(
      (category) => disabilityCategoryRequiredDocumentsMap[category] || []
    )
  );
  value = [...uniqueDocIds]
    .sort()
    .map((id) => requiredDocumentsMap[id])
    .filter(Boolean)
    .join("");
}
else{
  value ="";
}
